import{_ as a,o as t,c as o,ai as i}from"./chunks/framework.CsYGeNYI.js";const b=JSON.parse('{"title":"WebChat","description":"","frontmatter":{"summary":"Loopback WebChat static host and Gateway WS usage for chat UI","read_when":["Debugging or configuring WebChat access"],"title":"WebChat"},"headers":[],"relativePath":"web/webchat.md","filePath":"web/webchat.md","lastUpdated":1771906665000}'),c={name:"web/webchat.md"};function r(s,e,n,h,d,l){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="webchat-gateway-websocket-ui" tabindex="-1"><a class="header-anchor" href="#webchat-gateway-websocket-ui">#</a> WebChat (Gateway WebSocket UI)</h1><p>Status: the macOS/iOS SwiftUI chat UI talks directly to the Gateway WebSocket.</p><h2 id="what-it-is" tabindex="-1"><a class="header-anchor" href="#what-it-is">#</a> What it is</h2><ul><li>A native chat UI for the gateway (no embedded browser and no local static server).</li><li>Uses the same sessions and routing rules as other channels.</li><li>Deterministic routing: replies always go back to WebChat.</li></ul><h2 id="quick-start" tabindex="-1"><a class="header-anchor" href="#quick-start">#</a> Quick start</h2><ol><li>Start the gateway.</li><li>Open the WebChat UI (macOS/iOS app) or the Control UI chat tab.</li><li>Ensure gateway auth is configured (required by default, even on loopback).</li></ol><h2 id="how-it-works-behavior" tabindex="-1"><a class="header-anchor" href="#how-it-works-behavior">#</a> How it works (behavior)</h2><ul><li>The UI connects to the Gateway WebSocket and uses <code>chat.history</code>, <code>chat.send</code>, and <code>chat.inject</code>.</li><li><code>chat.inject</code> appends an assistant note directly to the transcript and broadcasts it to the UI (no agent run).</li><li>History is always fetched from the gateway (no local file watching).</li><li>If the gateway is unreachable, WebChat is read-only.</li></ul><h2 id="remote-use" tabindex="-1"><a class="header-anchor" href="#remote-use">#</a> Remote use</h2><ul><li>Remote mode tunnels the gateway WebSocket over SSH/Tailscale.</li><li>You do not need to run a separate WebChat server.</li></ul><h2 id="configuration-reference-webchat" tabindex="-1"><a class="header-anchor" href="#configuration-reference-webchat">#</a> Configuration reference (WebChat)</h2><p>Full configuration: <a href="/docs/gateway/configuration">Configuration</a></p><p>Channel options:</p><ul><li>No dedicated <code>webchat.*</code> block. WebChat uses the gateway endpoint + auth settings below.</li></ul><p>Related global options:</p><ul><li><code>gateway.port</code>, <code>gateway.bind</code>: WebSocket host/port.</li><li><code>gateway.auth.mode</code>, <code>gateway.auth.token</code>, <code>gateway.auth.password</code>: WebSocket auth.</li><li><code>gateway.remote.url</code>, <code>gateway.remote.token</code>, <code>gateway.remote.password</code>: remote gateway target.</li><li><code>session.*</code>: session storage and main key defaults.</li></ul>',16)])])}const w=a(c,[["render",r]]);export{b as __pageData,w as default};
